INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "リン", 0.0, "あたしだって\nやるときはやるよ！", 1, 10040, 24, 24001, 1, "2020/04/30 12:00:00", "2030/12/17 14:59:59", 0.0, 102601, 0);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "リン", 0.0, "ふぅ…\nこれであたしの仕事は\n終わりだね", 1, 10040, 24, 24002, 1, "2020/04/30 12:00:00", "2030/12/17 14:59:59", 0.0, 102601, 1);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "リン", 0.0, "終わった終わった\n一人でもなんとか\nなるもんだね", 1, 10040, 24, 24003, 1, "2020/04/30 12:00:00", "2030/12/17 14:59:59", 0.0, 102601, 2);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "リン", 0.0, "やったね！\nこれでようやく\nサボれるよ…", 2, 10040, 24, 24004, 2, "2020/04/30 12:00:00", "2030/12/17 14:59:59", 0.0, 102601, 3);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "リン", 0.0, "チーズが欲しいなら\nきちんと働いて\n買いに来なよ", 1, 10040, 24, 24005, 1, "2020/04/30 12:00:00", "2030/12/17 14:59:59", 0.0, 102601, 4);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "リン", 0.0, "あたしを敵に回した\n恐ろしさ\n思い知ったか！", 2, 10040, 24, 24006, 2, "2020/04/30 12:00:00", "2030/12/17 14:59:59", 0.0, 102601, 5);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "リン", 0.0, "あたしも意外と\nやるもんでしょ？", 2, 10040, 24, 24007, 2, "2020/04/30 12:00:00", "2030/12/17 14:59:59", 0.0, 102601, 6);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "リン", 0.0, "疲れた…\nねずみの逃げ足\n速すぎるよ…", 4, 10040, 24, 24008, 4, "2020/04/30 12:00:00", "2030/12/17 14:59:59", 0.0, 102601, 7);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "リン", 0.0, "このままじゃ\nまっひ～に\n叱られちゃうよ", 4, 10040, 24, 24009, 4, "2020/04/30 12:00:00", "2030/12/17 14:59:59", 0.0, 102601, 8);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "リン", 0.0, "まじめに\nやったんだけどな…\n悔しいな～", 4, 10040, 24, 24010, 4, "2020/04/30 12:00:00", "2030/12/17 14:59:59", 0.0, 102601, 9);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "リン", 0.0, "やられた…\nねずみって意外と\nてごわいね", 4, 10040, 24, 24011, 4, "2020/04/30 12:00:00", "2030/12/17 14:59:59", 0.0, 102601, 10);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (0.0, "リン", 0.0, "おのれ～\nあたしのチーズを\n盗みやがって～！", 4, 10040, 24, 24012, 4, "2020/04/30 12:00:00", "2030/12/17 14:59:59", 0.0, 102601, 11);
INSERT INTO `v1_eb2e4a41888c8abe85cbb691c8c1e18752332384ad7191a24cb6c07e9cf2a6f0` VALUES (1.81, "リン", 0.0, "疲れた…\nけど、次こそは\n守り抜くよ…", 1, 10040, 24, 24013, 4, "2020/04/30 12:00:00", "2030/12/17 14:59:59", 0.0, 102601, 12);
